#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to find all divisors of a number
void findDivisors(long long n, long long *divisors, int *count) {
    *count = 0;
    for (long long i = 1; i * i <= n; i++) {
        if (n % i == 0) {
            divisors[(*count)++] = i;
            if (i * i != n) {
                divisors[(*count)++] = n / i;
            }
        }
    }
}

// Function to calculate the score of a divisor tree
long long calculateScore(long long n) {
    long long score = 0;
    long long divisors[1000];
    int count;
    findDivisors(n, divisors, &count);
    for (int i = 0; i < count; i++) {
        score += calculateScore(divisors[i]) + 1;
    }
    return score;
}

int main() {
    long long A, B;
    scanf("%lld %lld", &A, &B);
    long long sum = 0;
    for (long long i = A; i <= B; i++) {
        sum += calculateScore(i);
    }
    printf("%lld\n", sum);
    return 0;
}

