// Function to find all divisors of a number
std::vector<long long> findDivisors(long long n) {
    std::vector<long long> divisors;
    for (long long i = 1; i * i <= n; i++) {
        if (n % i == 0) {
            divisors.push_back(i);
            if (i * i != n) {
                divisors.push_back(n / i);
            }
        }
    }
    return divisors;
}

// Function to calculate the score of a divisor tree
long long calculateScore(long long n) {
    long long score = 0;
    std::vector<long long> divisors = findDivisors(n);
    for (long long divisor : divisors) {
        score += calculateScore(divisor) + 1;
    }
    return score;
}

int main() {
    long long A, B;
    std::cin >> A >> B;
    long long sum = 0;
    for (long long i = A; i <= B; i++) {
        sum += calculateScore(i);
    }
