import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    // Function to find all divisors of a number
    public static ArrayList<Long> findDivisors(long n) {
        ArrayList<Long> divisors = new ArrayList<>();
        for (long i = 1; i * i <= n; i++) {
            if (n % i == 0) {
                divisors.add(i);
                if (i * i != n) {
                    divisors.add(n / i);
                }
            }
        }
        return divisors;
    }

    // Function to calculate the score of a divisor tree
    public static long calculateScore(long n) {
        long score = 0;
        ArrayList<Long> divisors = findDivisors(n);
        for (long divisor : divisors) {
            score += calculateScore(divisor) + 1;
        }
        return score;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        long A = scanner.nextLong();
        long B = scanner.nextLong();
        long sum = 0;
        for (long i = A; i <= B; i++) {
            sum += calculateScore(i);
        }
        System.out.println(sum);
