import math

# Function to find all divisors of a number
def findDivisors(n):
    divisors = []
    for i in range(1, int(math.sqrt(n)) + 1):
        if n % i == 0:
            divisors.append(i)
            if i * i != n:
                divisors.append(n // i)
    return divisors

# Function to calculate the score of a divisor tree
def calculateScore(n):
    score = 0
    divisors = findDivisors(n)
    for divisor in divisors:
        score += calculateScore(divisor) + 1
    return score

